// On lit l'article qui arrive du nœud Loop
const item = $input.item.json;

// On construit un prompt détaillé pour Gemini
const promptText = `**Rôle et Contexte :** Tu es un journaliste interne pour la newsletter "Le Mag'" de l'entreprise TB Groupe. Ton style est engageant, positif et professionnel mais décontracté. Je ne veux pas que tu sois dans l'exagération ou dans l'extrapolation.

**Mission :** Prends les informations brutes suivantes et transforme-les en un court article pour la newsletter.
- **Pour le Titre :** Tu dois **impérativement réécrire et améliorer le titre** pour le rendre plus accrocheur, professionnel et engageant, même si le titre de base semble correct.
- **Pour le Contenu :** Tu peux réécrire, enrichir et améliorer le texte pour le rendre plus percutant. **Si le contenu (les idées du collaborateur) est déjà parfaitement écrit, tu peux le copier-coller. Ne modifie jamais un lien URL, garde le intacte**

**Données brutes à ne pas transformer :**
- Nom : "${item.name || 'Non fourni'}"
- Service : "${item.service || 'Non fourni'}"
- Lien et raccourcis 


**Données brutes à transformer :**
- Titre de base (à réécrire) : \"${item.Titre || 'Non fourni'}\"
- Idées du collaborateur : \"${item.message || 'Non fourni'}\"

**Instructions de style :**
- Ton engageant et positif
- Ajoute jusqu'à 2 émojis pertinents, n'utilises jamais celui ci : 🚀
- Inspire toi du style et du vocabulaire de nos sites internet : https://tb1648.com/ , https://tb-outdoor.com/
- Article de 150-300 mots maximum
- Mettre en valeur l'initiative du service
- Rendre le contenu accessible à tous les employés
- Rajoute des majuscules seulement au noms propres et début de phrases

**IMPORTANT :** Tu DOIS répondre UNIQUEMENT avec un objet JSON valide dans ce format exact :

{
  "title": "Le nouveau titre accrocheur et amélioré",
  "content": "Le contenu complet de l'article réécrit ou copié"
}

Pas de texte avant ou après le JSON. Uniquement le JSON.`;

// On retourne UNIQUEMENT le prompt
return {
  prompt: promptText,
  originalData: item 
};

const item = $input.item.json;

// Utilise le titre et le message originaux
const finalTitle = item.Titre || 'Titre non fourni';
const finalContent = item.message || '';

// Retourne un objet formaté pour la suite
return {
  ...item,
  title: finalTitle,
  content: `<p>${finalContent.replace(/\n/g, '</p><p>')}</p>`,
};

// Le nœud Merge a combiné les données. Tout est dans $input.item.json.
const mergedData = $input.item.json;

// Les données originales viennent de l'Input 1 du Merge
const initialData = mergedData.originalData;

// La réponse de l'IA vient de l'Input 2 du Merge
const geminiResponse = mergedData.content;

// --- Vérifications ---
if (!geminiResponse?.parts?.[0]?.text) {
  throw new Error("La réponse de l'IA est invalide ou vide.");
}
if (!initialData) {
  throw new Error("Données originales non trouvées. Vérifiez la connexion vers l'Input 1 du nœud Merge.");
}

// --- Parsing et création de l'objet ---
try {
  let jsonString = geminiResponse.parts[0].text;
  jsonString = jsonString.trim().replace(/^```json/g, '').replace(/```$/g, '');

  const articleObject = JSON.parse(jsonString);

  // --- OBJET DE RETOUR MODIFIÉ ---
  return {
    ...initialData, //.
    title: articleObject.title || initialData.Titre || 'Titre non trouvé', // Utilise le titre de l'IA, ou le titre original en secours
    content: `<p>${(articleObject.content || '').replace(/\n/g, '</p><p>')}</p>`,
  };

} catch (error) {
  throw new Error(`Erreur de parsing JSON. Contenu reçu : "${jsonString}"`);
}

const item = $input.item.json;
const authorName = item.name.trim();
const serviceName = item.service.trim();

// --- 1. Tables de correspondance ---
const authorMap = {
  "ADV": 4, "Anthony": 2, "Bureau Etude": 5, "Commerce": 6,
  "Compta": 7, "Design": 8, "Direction": 9, "Emeline": 1,
  "Expeditions": 10, "Informatique": 11, "Logistique": 12,
  "n8n": 17, "Production": 13, "Qualite/Méthode": 14, "SamySel": 16, "Web": 15, "RH":19,
};
const defaultAuthorId = 1;

const categoryMap = {
  "IA": 4, "Métier": 6, "Produit": 5,
  "Tech": 3, "Vie d'entreprise": 1,
};
const defaultCategoryId = 1;

// --- 2. CORRECTION DE L'URL POUR DOCKER ---
// On vérifie si un fichier existe avant de tenter de remplacer l'URL
if (item.fichier) {
  // On remplace l'ancienne adresse par la nouvelle
  item.fichier = item.fichier.replace('host.docker.internal', '172.17.0.1');
}

// --- 3. Recherche des ID ---
item.authorId = authorMap[authorName] || defaultAuthorId;
item.categoryId = categoryMap[serviceName] || defaultCategoryId;

// --- 4. Création d'un nom de fichier unique ---
if (item.fichier) {
  const originalFilename = item.fichier.split('/').pop();
  const parts = originalFilename.split('.');
  const extension = parts.pop();
  const nameWithoutExt = parts.join('.');
  const randomString = Math.random().toString(36).substring(2, 8);
  item.uniqueFilename = `${nameWithoutExt}-${randomString}.${extension}`;
}

// On retourne l'objet enrichi
return item;

const item = $input.item.json;

// --- 1. Logique de Titre Robuste ---
let finalTitle = "Titre non fourni";

// On priorise le titre généré par Gemini Ultra
if (item.title && typeof item.title === 'string' && item.title.length > 0) {
  finalTitle = item.title;
} 
// En secours, on prend le titre original saisi dans Elementor
else if (item.Titre && typeof item.Titre === 'string' && item.Titre.length > 0) {
  finalTitle = item.Titre;
}

// --- 2. Logique d'Image (Featured Media) ---
let image_id = undefined;

// On vérifie les différentes sources d'ID média possibles
if (item.id) {
  image_id = item.id;
} else if (item.image_id) {
  image_id = item.image_id;
} else if (item.featured_media) {
  image_id = item.featured_media;
} else if (Array.isArray(item.body) && item.body.length > 0 && item.body[0].id) {
  image_id = item.body[0].id;
}

// --- 3. Construction du Contenu avec IP ---
let articleContent = item.content || item.message || "";
const authorIP = item.user_ip || "Inconnue";

// On ajoute un séparateur et la mention de l'IP en bas de l'article
articleContent += `\n\n<br><br><hr><p style="font-size: 11px; color: #777; font-style: italic;">
Source de la soumission : Intranet TB Groupe<br>
Adresse IP de l'auteur : ${authorIP}
</p>`;

// --- 4. Construction du Payload pour WordPress ---
const postBody = {
  title: finalTitle,
  content: articleContent,
  author: item.authorId || 1,        // ID traduit par le nœud précédent
  categories: [item.categoryId || 1], // WordPress attend souvent un tableau d'IDs
  status: 'draft',                   // Toujours en brouillon pour validation
  comment_status: 'open'             // Permet les commentaires via wpDiscuZ
};

// Si une image a été uploadée (IA ou Auteur), on l'attache
if (image_id) {
  postBody.featured_media = image_id;
}

// --- 5. Sortie du nœud ---
return {
  json: {
    postBody,
    originalSubmissionId: item.submission_id
  }
};

const item = $input.item.json;

// --- Customize Prompt Details ---
// Style général de l'illustration
const style_keywords = "illustration conceptuelle, moderne, épurée, aux couleurs vives et professionnelles. Ne pas utiliser de symboles de couteaux ou d'objets tranchants. Utilise une palette de couleurs proche de celle de TB Groupe (noir, rouge, gris, blanc) mais peut incorporer d'autres couleurs pour le dynamisme.";

// Ce qu'il faut absolument éviter
const negative_prompt = "texte, mots, lettres, chiffres, logos explicites, photoréaliste, agressif, caricatural. Éviter les stéréotypes trop marqués ou les scènes génériques.";

// --- Spécification du Clin d'œil TB/GDD ---
// L'IA est encouragée à interpréter cela de manière subtile, par exemple via l'intégration de formes, de motifs, ou une esthétique qui rappelle nos produits sans les montrer directement.
// Exemples : des lignes épurées et précises, des textures métalliques douces, une composition qui évoque la qualité ou l'innovation.
const company_nod = "Intègre subtilement un clin d'œil à l'identité de TB Groupe et GDD, par des formes, une ambiance ou des motifs qui évoquent la précision, la qualité ou l'innovation industrielle, sans montrer de produits spécifiques comme des couteaux.";
// --------------------------------

// Combine elements for the main prompt description
const main_prompt = `Génère une illustration pour une newsletter interne. L'image doit être directement pertinente et visuellement explicite par rapport au contenu de l'article.
Le sujet principal de l'article est : "${item.title}".
Les idées clés et le contexte du message sont : "${item.message.substring(0, 300)}".
Le style doit être ${style_keywords}.
${company_nod}
N'ajoute absolument aucun texte sur l'image, ni le titre, ni le nom de l'entreprise, ni aucun autre mot.`;

// Generate a unique filename
const randomString = Math.random().toString(36).substring(2, 8);
item.uniqueFilename = `generated-${item.submission_id}-${randomString}.png`;

// Structure the output as JSON for an image generation API
const imageGenerationJson = {
  "prompt": main_prompt,
  "n": 1, // Number of images to generate
  "size": "1024x1024", // Desired image size (check API docs)
  "response_format": "b64_json", // Request Base64 encoded image data
  "style_preset": "digital-art", // Vous pouvez aussi essayer "flat-design", "vector-art"
  "negative_prompt": negative_prompt
};

// Return the item data along with the structured JSON prompt
return {
  ...item, // Keep original data
  uniqueFilename: item.uniqueFilename, // Ensure unique filename is passed
  imageGenerationPrompt: imageGenerationJson // The JSON object for the next node
};
